import{_ as s,c as a,o as i,d}from"./plugin-vue_export-helper.f7ed9f25.js";const h='{"title":"\u0413\u043B\u0430\u0432\u0430 2","description":"","frontmatter":{"title":"\u0413\u043B\u0430\u0432\u0430 2","subtitle":"\u041C\u0430\u043B\u0438\u043D\u0438 \u0432\u0438\u0434\u0436\u0430\u0439\u043E\u0442\u0442\u0430\u0440\u0430 \u0442\u0430\u043D\u0442\u0440\u0430","tags":"malini","date":"2020-11-01T00:00:00.000Z"},"relativePath":"texts/malini-vijayottara/2.md","lastUpdated":1624912558481}',e={},n=d('<div class="stanza"><a href="#s2.1" id="s2.1" class="num">2.1</a><p>\u0411\u0445\u0430\u0439\u0440\u0430\u0432\u0430 \u0441\u043A\u0430\u0437\u0430\u043B:</p><p>\u0422\u0435\u043F\u0435\u0440\u044C \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u0432\u043A\u0440\u0430\u0442\u0446\u0435 \u043F\u043E \u043F\u043E\u0440\u044F\u0434\u043A\u0443 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 \u0442\u0430\u0442\u0442\u0432, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0437\u0435\u043C\u043B\u0438, \u0440\u0430\u0434\u0438 \u0443\u0441\u043F\u0435\u0445\u0430 \u0432 \u0439\u043E\u0433\u0435 \u0439\u043E\u0433\u0438\u043D\u043E\u0432</p></div><div class="stanza"><a href="#s2.2" id="s2.2" class="num">2.2</a><p><em>\u041F\u0440\u0438\u0442\u0445\u0438\u0432\u0438 \u0442\u0430\u0442\u0442\u0432\u0430</em> (\u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u0437\u0435\u043C\u043B\u0438, \u0433\u0440\u0443\u0431\u0430\u044F, \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u0430\u044F \u043C\u0430\u0442\u0435\u0440\u0438\u044F) \u0440\u0430\u0437\u0434\u0435\u043B\u044F\u0435\u0442\u0441\u044F \u043D\u0430 \u0448\u0430\u043A\u0442\u0438, \u043E\u0431\u043B\u0430\u0434\u0430\u0442\u0435\u043B\u044F \u0448\u0430\u043A\u0442\u0438 \u0438 <em>\u0441\u0432\u0430\u0440\u0443\u043F\u0443</em>, \u043E\u043D\u0430 (<em>\u043F\u0440\u0438\u0442\u0445\u0438\u0432\u0438</em> <em>\u0442\u0430\u0442\u0442\u0432\u0430</em>) \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F \u043A\u0430\u043A \u043F\u044F\u0442\u044C\u0434\u0435\u0441\u044F\u0442 (\u0441\u043B\u043E\u0433\u043E\u0432 \u043C\u0430\u0442\u0440\u0438\u043A\u0438).</p></div><div class="stanza"><a href="#s2.3" id="s2.3" class="num">2.3</a><p>\u041D\u0430\u0434\u0435\u043B\u0435\u043D\u043D\u044B\u0435_ \u0430\u0442\u043C\u0430\u043D\u043E\u043C_, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0428\u0438\u0432\u044B \u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044F <em>\u0441\u0430\u043A\u0430\u043B\u043E\u0439</em> \u0438\u043C\u0435\u043D\u0443\u044E\u0442\u0441\u044F <em>\u0448\u0430\u043A\u0442\u0438\u043C\u0430\u043D\u0430\u043C\u0438</em> (\u043E\u0431\u043B\u0430\u0434\u0430\u0442\u0435\u043B\u044F\u043C\u0438 \u0448\u0430\u043A\u0442\u0438), \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u043C\u043E\u0435 \u0438\u043C\u0438 \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E \u043A\u0430\u043A <em>\u0428\u0430\u043A\u0442\u0438</em>.</p></div><div class="stanza"><a href="#s2.4" id="s2.4" class="num">2.4</a><p>\u041D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0432\u043E\u0434\u044B \u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044F <em>\u043C\u0443\u043B\u0430</em> <em>\u043F\u0440\u0430\u043A\u0440\u0438\u0442\u0438</em> \u044D\u0442\u0430 \u0432\u0435\u043B\u0438\u043A\u0430\u044F \u0441\u043E\u0432\u043E\u043A\u0443\u043F\u043D\u043E\u0441\u0442\u044C <em>\u0442\u0430\u0442\u0442\u0432</em> \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F \u0436\u0435\u043B\u0430\u044E\u0449\u0438\u043C\u0438 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0430 (\u043A\u0430\u0440\u043C\u044B) \u043A\u0430\u043A \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u044C.</p></div><div class="stanza"><a href="#s2.5" id="s2.5" class="num">2.5</a><p>\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u043E\u0442 <em>\u043F\u0443\u0440\u0443\u0448\u0430 \u0442\u0430\u0442\u0432\u044B</em> \u0438 \u0434\u043E <em>\u043A\u0430\u043B\u0410 \u0442\u0430\u0442\u0442\u0432\u044B</em> \u043D\u0430\u0441\u0447\u0438\u0442\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u043C\u043E\u0435 - \u0442\u0440\u0438\u043D\u0430\u0434\u0446\u0430\u0442\u044C <em>\u043F\u0440\u0430\u043B\u0430\u0439\u0430 \u043A\u0430\u043B\u0430</em> (\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u043F\u043E\u043B\u043D\u043E\u0439 \u043F\u043E\u0433\u0440\u0443\u0436\u0435\u043D\u043D\u043E\u0441\u0442\u0438 \u0432 \u043C\u0430\u0439\u044E), \u043F\u043E\u0434\u043E\u0431\u043D\u044B\u0445 \u0420\u0443\u0434\u0440\u0435.</p></div><div class="stanza"><a href="#s2.6" id="s2.6" class="num">2.6</a><p>\u0422\u0430\u043A\u043E\u0432\u0430 \u0436\u0435 (<em>\u043F\u0440\u0430\u043B\u0430\u0439\u0430 \u043A\u0430\u043B\u0430</em>) \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u043C\u0430\u044F \u041C\u0430\u0439\u0430, \u043E\u043D\u0430 \u0434\u0435\u0432\u044F\u0442\u0438\u0440\u0438\u0447\u043D\u0430\u044F, \u0446\u0435\u043B\u044C\u043D\u043E\u0435 \u0417\u043D\u0430\u043D\u0438\u0435. \u041C\u0430\u043D\u0442\u0440 - \u0441\u0435\u043C\u044C \u0432\u0438\u0434\u043E\u0432, \u043F\u044F\u0442\u044C \u0432\u0438\u0434\u043E\u0432 \u0432\u043B\u0430\u0434\u044B\u043A \u043C\u0430\u043D\u0442\u0440 (<em>\u043C\u0430\u043D\u0442\u0440\u0430\u043D\u0430\u044F\u043A\u0430</em>).</p></div><div class="stanza"><a href="#s2.7" id="s2.7" class="num">2.7</a><p>(\u0421\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u044E\u0442) \u0442\u0440\u043E\u0435 \u043C\u0430\u043D\u0442\u0440\u0435\u0448\u0432\u0430\u0440, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043D\u0435\u043E\u0442\u0434\u0435\u043B\u0438\u043C\u044B \u043E\u0442 \u0428\u0438\u0432\u044B. \u0422\u0430\u043A \u0432\u043A\u0440\u0430\u0442\u0446\u0435 \u043E\u043F\u0438\u0441\u0430\u043D\u043E \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0435 (\u0435\u0434\u0438\u043D\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F), \u0431\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0433\u043E \u0438 \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u044F\u044E\u0449\u0435\u0433\u043E\u0441\u044F.</p></div><div class="stanza"><a href="#s2.8" id="s2.8" class="num">2.8</a><p>\u0422\u0430\u043A \u044D\u0442\u0438\u043C\u0438 \u0434\u0435\u043B\u0435\u043D\u0438\u044F\u043C\u0438 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0446\u0435\u043F\u044C \u043C\u0438\u0440\u043E\u0432. \u0420\u0430\u0434\u0438 \u0443\u0441\u043F\u0435\u0445\u0430 \u0432 \u0439\u043E\u0433\u0435 \u043E\u043D\u0430 \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F \u0439\u043E\u0433\u0438\u043D\u0430\u043C\u0438 \u0438 \u043F\u043E\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044F \u0439\u043E\u0433\u043E\u0439.</p></div><div class="stanza"><a href="#s2.9" id="s2.9" class="num">2.9</a><p>\u041A\u0442\u043E \u0437\u043D\u0430\u0435\u0442 \u044D\u0442\u0438 \u0421\u0443\u0449\u043D\u043E\u0441\u0442\u0438 \u0438 \u044D\u0442\u0438 \u043C\u0438\u0440\u044B, \u043A\u0430\u043A \u0415\u0434\u0438\u043D\u043E\u0435, \u043E\u0431\u0440\u0435\u0442\u0435\u0442 \u043F\u043B\u043E\u0434 \u0439\u043E\u0433\u0438, \u043E \u0428\u0430\u043D\u043A\u0430\u0440\u0438.</p></div><div class="stanza"><a href="#s2.10" id="s2.10" class="num">2.10</a><p>\u041A\u0442\u043E \u0432\u043E\u0438\u0441\u0442\u0438\u043D\u0443 \u0442\u0430\u043A\u0436\u0435 \u043F\u043E\u0437\u043D\u0430\u0435\u0442 \u0432\u0441\u0435 \u0442\u0430\u0442\u0442\u0432\u044B, \u0442\u043E\u0442 \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0413\u0443\u0440\u0443 \u0440\u0430\u0432\u043D\u044B\u043C \u041C\u043D\u0435, \u044F\u0432\u043B\u044F\u044E\u0449\u0438\u043C \u0441\u0438\u043B\u0443 \u043C\u0430\u043D\u0442\u0440\u044B.</p></div><div class="stanza"><a href="#s2.11" id="s2.11" class="num">2.11</a><p>\u041B\u044E\u0434\u0438 \u043F\u0440\u0438\u043A\u0430\u0441\u0430\u044F\u0441\u044C (\u043A \u043D\u0435\u043C\u0443), \u0431\u0435\u0441\u0435\u0434\u0443\u044F \u0441 \u043D\u0438\u043C, \u0432\u0438\u0434\u044F \u0435\u0433\u043E, \u0441 \u0443\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u0435\u043D\u043D\u044B\u043C \u0443\u043C\u043E\u043C \u0438\u0437\u0431\u0430\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u043E\u0442 \u0432\u0441\u0435\u0445 \u0433\u0440\u0435\u0445\u043E\u0432, \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u044B\u0445 \u0432 \u0442\u0435\u0447\u0435\u043D\u0438\u0438 \u0441\u0435\u043C\u0438 \u0440\u043E\u0436\u0434\u0435\u043D\u0438\u0439.</p></div><div class="stanza"><a href="#s2.12" id="s2.12" class="num">2.12</a><p>\u0410 \u0442\u0435, \u0436\u0438\u0432\u0443\u0449\u0438\u0435, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043F\u043E\u0441\u0432\u044F\u0449\u0435\u043D\u044B \u0438\u043C, (\u0441\u0442\u0430\u043D\u043E\u0432\u044F\u0442\u0441\u044F) \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435\u043C \u0428\u0438\u0432\u044B, \u043E\u0431\u0440\u0435\u0442\u044F \u043F\u043B\u043E\u0434 \u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0436\u0435\u043B\u0430\u043D\u0438\u044E, \u043E\u043D\u0438 \u043E\u0431\u0440\u0435\u0442\u0443\u0442 \u0432\u044B\u0441\u0448\u0435\u0435 \u043F\u043E\u043B\u043E\u0436\u0435\u043D\u0438\u0435.</p></div><div class="stanza"><a href="#s2.13" id="s2.13" class="num">2.13</a><p>\u0412 \u043D\u0435\u043C \u0432\u0435\u0447\u043D\u043E \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 \u0432\u043E \u0432\u0437\u0430\u0438\u043C\u043E\u043F\u0440\u043E\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u0438 \u0420\u0443\u0434\u0440\u0430 \u0438 \u0428\u0430\u043A\u0442\u0438. \u0412 \u044D\u0442\u043E\u0439 \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u044B\u0434\u0435\u043B\u0438\u0442\u044C \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u0435 \u043F\u0440\u0438\u0437\u043D\u0430\u043A\u0438:</p></div><div class="stanza"><a href="#s2.14" id="s2.14" class="num">2.14</a><p>\u041F\u0435\u0440\u0432\u044B\u0439 \u043F\u0440\u0438\u0437\u043D\u0430\u043A - \u043D\u0435\u043A\u043E\u043B\u0435\u0431\u0438\u043C\u0430\u044F \u043F\u0440\u0435\u0434\u0430\u043D\u043D\u043E\u0441\u0442\u044C \u0420\u0443\u0434\u0440\u0435. \u0412\u0442\u043E\u0440\u043E\u0439 - \u043C\u0430\u043D\u0442\u0440\u0430 \u0441\u0438\u0434\u0434\u0445\u0438 \u0442\u0432\u043E\u0440\u044F\u0449\u0430\u044F \u0432\u0441\u044E \u0432\u0435\u0440\u0443</p></div><div class="stanza"><a href="#s2.15" id="s2.15" class="num">2.15</a><p>\u0422\u0440\u0435\u0442\u0438\u0439 \u043F\u0440\u0438\u0437\u043D\u0430\u043A - \u043F\u043E\u0434\u0447\u0438\u043D\u0435\u043D\u0438\u0435 \u0432\u0441\u0435\u0445 \u0442\u0430\u0442\u0442\u0432. \u0427\u0435\u0442\u0432\u0435\u0440\u0442\u044B\u0439 - \u0438\u0437\u0431\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u043E\u0442 \u043F\u0440\u043E\u0440\u043E\u0441\u0448\u0435\u0439 \u043A\u0430\u0440\u043C\u044B</p></div><div class="stanza"><a href="#s2.16" id="s2.16" class="num">2.16</a><p>\u041F\u044F\u0442\u044B\u0439 - \u043F\u043E\u044D\u0442\u0438\u0447\u043D\u043E\u0441\u0442\u044C, \u0437\u043D\u0430\u043D\u0438\u0435 \u043F\u043E\u044D\u0442\u0438\u0447\u0435\u0441\u043A\u0438\u0445 \u0443\u043A\u0440\u0430\u0448\u0435\u043D\u0438\u0439, \u0440\u0430\u0434\u0443\u044E\u0449\u0438\u0445 \u0443\u043C, \u043E\u0442 \u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0437\u043D\u0430\u043D\u0438\u0435 \u0441\u043C\u044B\u0441\u043B\u0430 \u0432\u0441\u0435\u0445 \u043F\u0438\u0441\u0430\u043D\u0438\u0439.</p></div><div class="stanza"><a href="#s2.17" id="s2.17" class="num">2.17</a><p>\u0412\u0437\u0430\u0438\u043C\u043E\u043F\u0440\u043E\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u0435 \u0420\u0443\u0434\u0440\u044B \u0438 \u0428\u0430\u043A\u0442\u0438 - \u043F\u044F\u0442\u0438\u0440\u0438\u0447\u043D\u043E. \u042D\u0442\u043E (\u0433\u0440\u0443\u0431\u044B\u0435) \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u044B, \u0442\u0430\u0442\u0442\u0432\u044B, \u0410\u0442\u043C\u0430\u043D, \u041C\u0430\u043D\u0442\u0440\u0435\u0448\u0430 \u0438 \u0428\u0430\u043A\u0442\u0438, \u043E \u041F\u0440\u0435\u043A\u0440\u0430\u0441\u043D\u043E\u043B\u0438\u043A\u0430\u044F!</p></div><div class="stanza"><a href="#s18-19" id="s18-19" class="num">18-19</a><p>\u042D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432 \u043D\u0430\u0441\u0447\u0438\u0442\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u043F\u044F\u0442\u044C, \u0430 \u0442\u0430\u043A\u0436\u0435 \u0442\u0440\u0438\u043D\u0430\u0434\u0446\u0430\u0442\u044C, \u0410\u0442\u043C\u0430\u043D \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0442\u0440\u0435\u0445 \u0432\u0438\u0434\u043E\u0432, \u043C\u0430\u043D\u0442\u0440\u0435\u0448\u0430 \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0434\u0435\u0441\u044F\u0442\u0438 \u0432\u0438\u0434\u043E\u0432. \u0412 \u0432\u044B\u0441\u0448\u0435\u043C \u0441\u043C\u044B\u0441\u043B\u0435 \u041F\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u043C\u0430\u044F \u0428\u0430\u043A\u0442\u0438 \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u0430 \u0434\u0432\u0443\u0445 \u0432\u0438\u0434\u043E\u0432. \u041F\u043E\u0433\u0440\u0443\u0436\u0435\u043D\u0438\u0435 (\u0432 \u0412\u044B\u0441\u0448\u0443\u044E \u0440\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C) \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u043F\u043E\u0434\u0435\u043B\u0435\u043D\u043D\u044B\u043C \u043D\u0430 \u043F\u044F\u0442\u044C\u0434\u0435\u0441\u044F\u0442.</p></div><div class="stanza"><a href="#s2.20" id="s2.20" class="num">2.20</a><p>(\u041C\u0435\u0442\u043E\u0434\u044B) \u043F\u043E\u0433\u0440\u0443\u0436\u0435\u043D\u0438\u044F (\u0432 \u0412\u044B\u0441\u0448\u0443\u044E \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C) \u0438\u043C\u0435\u043D\u0443\u044E\u0442\u0441\u044F \u0410\u043D\u0430\u0432\u0430, \u0428\u0430\u043A\u0442\u0430 \u0438 \u0428\u0430\u043C\u0431\u0445\u0430\u0432\u0430</p></div><div class="stanza"><a href="#s2.21" id="s2.21" class="num">2.21</a><p>(\u041C\u0435\u0442\u043E\u0434) \u043F\u043E\u0433\u0440\u0443\u0436\u0435\u043D\u0438\u044F (\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u0432 \u0432\u044B\u0441\u0448\u0443\u044E \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C), \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F <em>\u0443\u0447\u0447\u0430\u0440\u0430\u043D\u0435</em>, <em>\u043A\u0430\u0440\u0430\u043D\u0435</em>, <em>\u0434\u0445\u0439\u0410\u043D\u0435</em>, <em>\u0432\u0430\u0440\u043D\u0435</em> \u0438 _\u0441\u0442\u0445\u0430\u043D\u0430 \u043F\u0440\u0430\u043A\u0430\u043B\u044C\u043F\u0430\u043D\u0435 _\u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F <em>\u0430\u043D\u0430\u0432\u0430</em></p></div><div class="stanza"><a href="#s2.22" id="s2.22" class="num">2.22</a><p>(\u041C\u0435\u0442\u043E\u0434) \u043F\u043E\u0433\u0440\u0443\u0436\u0435\u043D\u0438\u044F (\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u0432 \u0432\u044B\u0441\u0448\u0443\u044E \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C), \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043D\u0438\u0435\u043C \u0432 \u0443\u043C\u0435 \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u0431\u0435\u0437 (\u043A\u0430\u043A\u043E\u0439 \u043B\u0438\u0431\u043E) <em>\u0443\u0447\u0447\u0430\u0440\u044B</em> (\u043F\u0440\u043E\u0438\u0437\u043D\u0435\u0441\u0435\u043D\u0438\u044F) \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0448\u0430\u043A\u0442\u0430</p></div><div class="stanza"><a href="#s2.23" id="s2.23" class="num">2.23</a><p>\u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0441\u0432\u043E\u0431\u043E\u0434\u0435 \u043E\u0442 \u0432\u0441\u044F\u043A\u043E\u0433\u043E \u043C\u0435\u043D\u0442\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u0438\u0437\u043C\u044B\u0448\u043B\u0435\u043D\u0438\u044F, \u0430 \u0442\u043E\u043B\u044C\u043A\u043E \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0435\u043D\u0438\u044E \u0423\u0447\u0438\u0442\u0435\u043B\u0435\u043C, \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442 \u043F\u043E\u0433\u0440\u0443\u0436\u0435\u043D\u0438\u0435 \u0432 (\u0428\u0438\u0432\u0443) \u044D\u0442\u043E \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0448\u0430\u043C\u0431\u0445\u0430\u0432\u0430 (\u0443\u043F\u0430\u0439\u0430)</p></div><div class="stanza"><a href="#s2.24" id="s2.24" class="num">2.24</a><p>\u041A\u0430\u043A \u0438 \u043F\u0440\u0435\u0436\u0434\u0435, \u043E\u043D\u043E \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u043F\u044F\u0442\u044C\u044E\u0434\u0435\u0441\u044F\u0442\u044C\u044E \u0440\u0430\u0437\u043D\u043E\u0432\u0438\u0434\u043D\u043E\u0441\u0442\u044F\u043C\u0438, (\u043D\u0430\u0447\u0438\u043D\u0430\u044F) \u0441 \u043A\u0440\u0430\u0442\u043A\u043E\u0433\u043E, \u0438 (\u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044F) \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u043D\u044B\u043C, \u043D\u0435 \u0437\u043D\u0430\u044E\u0449\u0438\u043C \u0438\u0441\u0447\u0438\u0441\u043B\u0435\u043D\u0438\u044F</p></div><div class="stanza"><a href="#s2.25-26" id="s2.25-26" class="num">2.25-26</a><p>\u0423 \u043F\u043B\u043E\u0434\u0430 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u043D\u0435 \u0432\u044B\u0434\u0435\u043B\u044F\u0435\u0442\u0441\u044F \u0434\u0435\u043B\u0435\u043D\u0438\u044F \u0434\u0430\u0436\u0435 \u043C\u0443\u0434\u0440\u044B\u043C\u0438. \u0420\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0435 \u0435\u0441\u0442\u044C \u043D\u0438\u0437\u0448\u0430\u044F (\u0430\u043F\u0430\u0440\u0430 \u0448\u0430\u043A\u0442\u0438), \u043E\u043D\u0430 \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u0438 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0435\u0442\u0441\u044F \u0432\u043A\u0440\u0430\u0442\u0446\u0435. \u0411\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435, \u0441\u043E\u043D \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438 \u0438 \u043F\u0440\u043E\u0447\u0438\u0435 (\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F) \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B \u043C\u0443\u0434\u0440\u044B\u043C \u043A\u0430\u043A \u043F\u044F\u0442\u0438\u0440\u0438\u0447\u043D\u043E\u0441\u0442\u044C, \u043E\u0442\u043B\u0438\u0447\u043D\u044B\u0435 \u043A\u0430\u0436\u0434\u044B\u0435 \u043F\u043E \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 \u0434\u0440\u0443\u0433 \u043E\u0442 \u0434\u0440\u0443\u0433\u0430.</p></div><div class="stanza"><a href="#s2.27" id="s2.27" class="num">2.27</a><p>\u0412 \u043D\u0438\u0445 (\u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442) \u0442\u0440\u0438\u0430\u0434\u0430: \u0412\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u044F\u044F \u0421\u0443\u0449\u043D\u043E\u0441\u0442\u044C, \u0428\u0430\u043A\u0442\u0438 \u0438 \u0441\u0430\u043A\u0430\u043B\u0430 (\u0441\u043E\u0432\u043E\u043A\u0443\u043F\u043D\u043E\u0441\u0442\u044C \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u043E\u0432). \u042D\u0442\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F \u0438\u043C\u0435\u0435\u0442 \u043F\u044F\u0442\u044C\u0434\u0435\u0441\u044F\u0442 \u043F\u043E\u0434\u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0439</p></div><div class="stanza"><a href="#s2.28" id="s2.28" class="num">2.28</a><p>\u0412 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u0433\u043E \u0441\u043D\u0430 \u0438 \u0441\u043D\u0430 \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438 \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u044E\u0442\u0441\u044F \u0434\u0432\u0430 \u0441\u0443\u0431\u044A\u0435\u043A\u0442\u0430 \u0430\u043A\u0430\u043B\u0430. \u041C\u0430\u043D\u0442\u0440\u0430 \u0438 \u043F\u0440\u043E\u0447\u0435\u0435, \u0435\u0435 \u043F\u043E\u043A\u0440\u043E\u0432\u0438\u0442\u0435\u043B\u044C, \u0418\u0448\u0430\u043D\u0430 \u0438 \u0432\u0430\u0440\u0433\u0430 (\u043F\u043E\u0440\u044F\u0434\u043E\u043A \u0442\u0430\u0442\u0442\u0432) \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0442\u0443\u0440\u0438\u0439\u0435\u0439</p></div><div class="stanza"><a href="#s2.29" id="s2.29" class="num">2.29</a><p>\u0428\u0430\u043A\u0442\u0438 \u0438 \u0428\u0430\u043C\u0431\u0445\u0443 \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u044E\u0442\u0441\u044F \u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 \u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u044F\u0449\u0438\u043C \u0442\u0443\u0440\u0438\u0439\u044E (\u0442\u0443\u0440\u0438\u0439\u0410\u0442\u0418\u0442\u0430), \u043E \u041F\u0440\u0435\u043A\u0440\u0430\u043D\u043E\u043B\u0438\u043A\u0430\u044F! \u041E\u0431\u0435 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u0435 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0438 \u0441\u0430\u043A\u0430\u043B\u044B, \u0441\u043E\u0441\u0442\u043E\u044F\u0442 \u0438\u0437 13 \u0434\u0435\u043B\u0435\u043D\u0438\u0439</p></div><div class="stanza"><a href="#s2.30" id="s2.30" class="num">2.30</a><p>\u041C\u0430\u043D\u0442\u0440\u043E\u0439, \u043C\u0430\u043D\u0442\u0440\u0435\u0448\u0432\u0430\u0440\u043E\u0439 \u0438 \u0438\u0448\u0430\u043D\u043E\u0439 \u0438\u043C\u0435\u043D\u0443\u044E\u0442\u0441\u044F \u043E\u0431\u0430 - \u0428\u0430\u043A\u0442\u0438 \u0438 \u0428\u0430\u043C\u0431\u0445\u0443 \u0432 (\u043E\u043F\u044B\u0442\u0435) <em>\u043F\u0440\u0430\u043B\u0430\u0439\u0430 \u043A\u0430\u043B\u0430</em> \u0438 \u0432 <em>\u0432\u0438\u0434\u0436\u043D\u0430\u043D\u0430 \u043A\u0430\u043B\u0430</em></p></div><div class="stanza"><a href="#s2.31" id="s2.31" class="num">2.31</a><p>\u041A\u0430\u043A \u0438 \u0440\u0430\u043D\u0435\u0435 \u0428\u0430\u043A\u0442\u0438 \u0438 \u0418\u0448\u0430 \u043F\u043E\u0434\u0440\u0430\u0437\u0434\u0435\u043B\u044F\u044E\u0442\u0441\u044F \u0434\u0435\u0432\u044F\u0442\u0438\u0440\u0438\u0447\u043D\u043E \u043D\u0430 \u043C\u0430\u043D\u0442\u0440\u0443, \u043C\u0430\u043D\u0442\u0440\u0435\u0448\u0432\u0430\u0440\u0443 \u0438 \u0418\u0448\u0430\u043D\u0443, \u043D\u0430 \u0441\u0430\u043C\u0438 \u043C\u0430\u043D\u0442\u0440\u044B \u0438 \u0443\u043F\u0440\u0430\u0432\u0438\u0442\u0435\u043B\u0435\u0439 \u043C\u0430\u043D\u0442\u0440\u044B</p></div><div class="stanza"><a href="#s2.32" id="s2.32" class="num">2.32</a><p>\u042D\u0442\u043E\u0442 \u0418\u0448\u0430, \u0428\u0430\u043A\u0442\u0438 \u0438 \u0428\u0430\u043C\u0431\u0445\u0443 \u0438\u043C\u0435\u043D\u0443\u044E\u0442\u0441\u044F \u043F\u044F\u0442\u044C\u044E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F\u043C\u0438 (\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F) \u043A\u0430\u043A \u0438 \u0440\u0430\u043D\u0435\u0435 \u043E\u043D\u0438 \u043F\u043E\u0434\u0440\u0430\u0437\u0434\u0435\u043B\u044F\u044E\u0442\u0441\u044F \u0441\u0435\u043C\u0435\u0440\u0438\u0447\u043D\u043E, \u043D\u0430 \u043C\u0430\u043D\u0442\u0440\u0443, \u0418\u0448\u0430\u043D\u0443 \u0438 \u0428\u0430\u043A\u0442\u0438</p></div><div class="stanza"><a href="#s2.33" id="s2.33" class="num">2.33</a><p>\u0428\u0438\u0432\u0430 \u0438\u0437\u0432\u0435\u0441\u0442\u0435\u043D \u043A\u0430\u043A \u041F\u044F\u0442\u0438\u0440\u0438\u0447\u043D\u043E\u0441\u0442\u044C, \u043E \u041F\u0440\u0435\u043A\u0440\u0430\u0441\u043D\u043E\u043B\u0438\u043A\u0430\u044F! \u0421\u0430\u043C\u0430 \u0428\u0430\u043A\u0442\u0438, \u0441\u043E \u0441\u0432\u043E\u0438\u043C \u0432\u043B\u0430\u0434\u044B\u043A\u043E\u0439, \u0428\u0430\u043A\u0442\u0438 \u0438 \u0428\u0430\u043C\u0431\u0445\u0443 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 \u0432 \u043F\u044F\u0442\u0438\u0440\u0438\u0447\u043D\u043E\u0441\u0442\u0438</p></div><div class="stanza"><a href="#s2.34-35" id="s2.34-35" class="num">2.34-35</a><p>\u0412 \u0442\u0440\u0438\u0430\u0434\u0435 \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F \u0428\u0438\u0432\u0430, \u0412\u043E\u043B\u044F \u0438 \u0428\u0430\u043A\u0442\u0438. \u041F\u043E\u043A\u0440\u043E\u0432\u0438\u0442\u0435\u043B\u044C\u0441\u0442\u0432\u0443\u044F \u0441\u043B\u0435\u0432\u0430 \u0438 \u0441\u043F\u0440\u0430\u0432\u0430 \u043F\u044F\u0442\u0438\u0440\u0438\u0447\u043D\u0430\u044F, \u043D\u043E \u043D\u0435\u0434\u0435\u043B\u0438\u043C\u0430\u044F \u0432\u043E\u043B\u044F \u043E\u0442 <em>\u043D\u0438\u0432\u0440\u0440\u0438\u0442\u0442\u0438 (\u043A\u0430\u043B\u0430)</em> (\u043E\u0441\u043E\u0437\u043D\u0430\u0432\u0430\u043D\u0438\u0435 \u0433\u0440\u0443\u0431\u043E\u0439 \u043C\u0430\u0442\u0435\u0440\u0438\u0438) \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 \u0421\u0435\u0431\u0435. \u0422\u0430\u043A \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u043C\u0430\u044F \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u044C \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u043F\u044F\u0442\u0438\u0440\u0438\u0447\u043D\u043E\u0441\u0442\u044C\u044E ..33-35.</p></div><div class="stanza"><a href="#s2.36" id="s2.36" class="num">2.36</a><p>\u0414\u0430\u043B\u0435\u0435 \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u044E\u0442\u0441\u044F \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 (\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F), \u0434\u0440\u043E\u0431\u044F\u0449\u0438\u0445 (\u0435\u0434\u0438\u043D\u043E\u0435) \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435. \u041F\u0440\u0435\u0431\u044B\u0432\u0430\u043D\u0438\u0435 \u0432 \u0442\u0435\u043B\u0435 <em>\u0421\u0430\u0440\u0432\u0430\u0442\u043E\u0431\u0445\u0430\u0434\u0440\u044B</em> \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0434\u0432\u043E\u044F\u043A\u0438\u043C \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435\u043C.</p></div><div class="stanza"><a href="#s2.37" id="s2.37" class="num">2.37</a><p>\u0414\u0432\u043E\u044F\u043A\u043E\u0433\u043E \u043F\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u044F \u0441\u043D\u0430 \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438 \u0436\u0435\u043B\u0430\u044E\u0442 (\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430), \u044D\u0442\u043E \u043F\u0440\u043E\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u0435 (\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F) \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0435\u0433\u043E \u0432 <em>\u043F\u0430\u0434\u0435</em>. \u0412\u0435\u043B\u0438\u043A\u043E\u0435 \u043F\u0440\u043E\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u0435 (\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F) \u0432 \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u043C \u0441\u043D\u0435 \u0435\u0441\u0442\u044C \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u043D\u0438\u0435 \u0432 \u0444\u043E\u0440\u043C\u0435. \u041E\u043D\u043E \u0442\u0430\u043A\u0436\u0435 \u0434\u0432\u043E\u044F\u043A\u043E.</p></div><div class="stanza"><a href="#s2.38" id="s2.38" class="num">2.38</a><p>\u0426\u0435\u043B\u043E\u0441\u0442\u043D\u043E\u0441\u0442\u044C (\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F), \u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u044F\u0449\u0430\u044F \u0444\u043E\u0440\u043C\u0443, \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0442\u0443\u0440\u0438\u0435\u0439. \u0412\u0435\u043B\u0438\u043A\u0443\u044E \u0446\u0435\u043B\u043E\u0441\u0442\u043D\u043E\u0441\u0442\u044C, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0435\u0441\u0442\u044C \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u044F\u0449\u0435\u0435 \u0442\u0443\u0440\u0438\u0439\u044E \u0436\u0435\u043B\u0430\u044E\u0442 (\u043E\u0431\u0440\u0435\u0441\u0442\u0438 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430).</p></div><div class="stanza"><a href="#s2.39" id="s2.39" class="num">2.39</a><p>\u0412\u0441\u0435 \u044D\u0442\u0438 \u043F\u044F\u0442\u044C \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0435\u0439 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0449\u0438\u0435 \u0440\u0430\u0437\u0434\u0440\u043E\u0431\u043B\u0435\u043D\u043D\u043E\u0441\u0442\u044C (\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F) \u0442\u0430\u043A\u0436\u0435 \u043F\u043E\u0434\u0440\u0430\u0437\u0434\u0435\u043B\u044F\u044E\u0442\u0441\u044F. \u0412\u044B\u0441\u043B\u0443\u0448\u0430\u0439 \u043E\u0431 \u044D\u0442\u043E\u043C.</p></div><div class="stanza"><a href="#s2.40-41" id="s2.40-41" class="num">2.40-41</a><p>\u0421\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0435 \u043F\u043E\u0437\u043D\u0430\u043D\u0438\u0435 \u0442\u0430\u0442\u0442\u0432 \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u043D\u0438\u0435\u043C \u0432 \u0439\u043E\u0433\u0435. (\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435) \u0438\u043C\u0435\u043D\u0443\u044E\u0442 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0438\u043C \u0432 \u0442\u0435\u043B\u0435, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0438\u043C \u0432 <em>\u043F\u0430\u0434\u0435</em>, \u043C\u0430\u043D\u0442\u0440\u0430\u043C\u0438 \u0438 \u0438\u0445 \u0432\u043B\u0430\u0434\u044B\u043A\u0430\u043C\u0438 \u0432\u043C\u0435\u0441\u0442\u0435 \u0441 \u0418\u0448\u0435\u0439 \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u043D\u0438\u0435 \u0432 \u0444\u043E\u0440\u043C\u0435. \u0412\u044B\u0448\u0435 \u0444\u043E\u0440\u043C - \u0412\u044B\u0441\u0448\u0430\u044F \u0428\u0430\u043A\u0442\u0438, \u043D\u0435\u0441\u0440\u0430\u0432\u043D\u0435\u043D\u043D\u0430\u044F, \u043E\u0431\u0440\u0435\u0442\u0430\u0435\u043C\u0430\u044F \u0441\u043F\u0440\u0430\u0432\u0430 \u0438 \u0441\u043B\u0435\u0432\u0430.</p></div><div class="stanza"><a href="#s2.42" id="s2.42" class="num">2.42</a><p>\u041D\u0435\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u044B\u0439, \u0411\u0435\u0441\u043F\u043E\u0434\u043E\u0431\u043D\u044B\u0439, \u0427\u0438\u0441\u0442\u044B\u0439, \u041F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0438\u0439 \u0432 \u0421\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u0421\u0443\u0449\u043D\u043E\u0441\u0442\u0438, \u0432\u0441\u0435\u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u044F\u0449\u0438\u0439, \u043F\u043E\u0437\u043D\u0430\u0432 \u041A\u043E\u0442\u043E\u0440\u043E\u0433\u043E (\u0439\u043E\u0433\u0438\u043D) \u043E\u0431\u0440\u0435\u0442\u0430\u0435\u0442 \u041E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u0435 \u0438\u0437\u0432\u0435\u0441\u0442\u0435\u043D \u043A\u0430\u043A \u0428\u0438\u0432\u0430.</p></div><div class="stanza"><a href="#s2.43-46" id="s2.43-46" class="num">2.43-46</a><p>\u041F\u0440\u0435\u0431\u044B\u0432\u0430\u043D\u0438\u0435 (\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F) \u0432 \u0442\u0435\u043B\u0435 (\u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E) \u0447\u0435\u0442\u044B\u0440\u0435\u0445 \u0432\u0438\u0434\u043E\u0432: \u043D\u0435 \u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0435\u043D\u043D\u043E\u0435, \u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0435\u043D\u043D\u043E\u0435, \u0445\u043E\u0440\u043E\u0448\u043E \u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0435\u043D\u043D\u043E\u0435, \u0438 \u0447\u0440\u0435\u0437\u0432\u044B\u0447\u0430\u0439\u043D\u043E \u0445\u043E\u0440\u043E\u0448\u043E \u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0435\u043D\u043D\u043E\u0435. \u041F\u0440\u0435\u0431\u044B\u0432\u0430\u043D\u0438\u0435 (\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F) \u0432 <em>\u043F\u0430\u0434\u0435</em> \u0442\u0430\u043A\u0436\u0435 \u0447\u0435\u0442\u044B\u0440\u0435\u0445 \u0432\u0438\u0434\u043E\u0432: \u043F\u0440\u0435\u0445\u043E\u0434\u044F\u0449\u0435\u0435 \u0438 \u0443\u0445\u043E\u0434\u044F\u0449\u0435\u0435, \u0440\u0430\u0441\u043F\u044B\u043B\u0435\u043D\u043D\u043E\u0435, \u0441\u043E\u0431\u0440\u0430\u043D\u043D\u043E\u0435, \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043D\u043D\u043E\u0435. \u041F\u0440\u0435\u0431\u044B\u0432\u0430\u043D\u0438\u0435 (\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F) \u0432 \u0444\u043E\u0440\u043C\u0435 \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E \u0447\u0435\u0442\u044B\u0440\u0435\u0445 \u0432\u0438\u0434\u043E\u0432 \u0438\u0441\u043A\u0443\u0448\u0435\u043D\u043D\u044B\u043C \u0432 \u0439\u043E\u0433\u0435: (\u044D\u0442\u043E) \u0440\u0430\u0441\u0442\u0443\u0449\u0435\u0435, \u043E\u0433\u0440\u043E\u043C\u043D\u043E\u0435, \u0441\u043F\u043E\u043A\u043E\u0439\u043D\u043E\u0435, \u0447\u0440\u0435\u0437\u0432\u044B\u0447\u0430\u0439\u043D\u043E \u0443\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u0435\u043D\u043D\u043E\u0435. \u0412 \u0433\u0440\u0443\u0434\u0435 \u0435\u0434\u0438\u043D\u043E\u0435 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0435\u0435 \u0432 \u043C\u0430\u0445\u0430\u0442\u0435 (\u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F) \u0443\u043C, \u0432\u043D\u0435 \u0443\u043C\u0430, \u0431\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0435, \u0440\u0430\u0441\u0442\u0443\u0449\u0435\u0435 \u0432\u043E \u0432\u0441\u0435 \u0441\u0442\u043E\u0440\u043E\u043D\u044B. \u0422\u0430\u043A\u043E\u0432\u0430 \u043F\u044F\u0442\u0438\u0440\u0438\u0447\u043D\u0430\u044F \u043F\u0440\u043E\u0442\u044F\u0436\u0435\u043D\u043D\u043E\u0441\u0442\u044C, \u043E\u043D\u0430 \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u0442\u0440\u043E\u044F\u043A\u043E.</p></div><div class="stanza"><a href="#s2.47" id="s2.47" class="num">2.47</a><p>\u0412\u043F\u043B\u043E\u0442\u044C \u0434\u043E _\u0432\u0438\u0434\u0436\u043D\u0430\u043D\u0430\u043A\u0430\u043B\u044B _\u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>\u0430\u0442\u043C\u0430 \u0442\u0430\u0442\u0442\u0432\u0430</em>, \u0437\u0430 \u0418\u0448\u0432\u0430\u0440\u0430 \u0442\u0430\u0442\u0442\u0432\u043E\u0439 (\u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F) \u0432\u0438\u0434\u0439\u0430 \u0442\u0430\u0442\u0442\u0432\u0430, \u043E\u0441\u0442\u0430\u043B\u044C\u043D\u043E\u0435 \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E \u043A\u0430\u043A \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0428\u0438\u0432\u044B (<em>\u0428\u0438\u0432\u0430 \u043F\u0430\u0434\u0430</em>).</p></div><div class="stanza"><a href="#s2.48" id="s2.48" class="num">2.48</a><p>\u042D\u0442\u0438\u043C\u0438 \u0434\u0435\u043B\u0435\u043D\u0438\u044F\u043C\u0438 \u0437\u0434\u0435\u0441\u044C \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u043F\u0440\u043E\u0442\u044F\u0436\u0435\u043D\u043D\u043E\u0441\u0442\u044C (\u0430\u0434\u0445\u0432\u0430). \u0422\u0435\u043F\u0435\u0440\u044C \u043E\u043F\u0438\u0441\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u043E\u0434\u043D\u043E\u0432\u0440\u0435\u043C\u0435\u043D\u043D\u043E\u0435 \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0435 \u0432\u0441\u0435\u0445 \u043F\u0443\u0442\u0435\u0439.</p></div><div class="stanza"><a href="#s2.49" id="s2.49" class="num">2.49</a><p>\u0417\u0435\u043C\u043B\u044F, \u043F\u0440\u0430\u043A\u0440\u0438\u0442\u0438, \u043C\u0430\u0439\u0430 \u0438 \u0448\u0430\u043A\u0442\u0438, \u0442\u0430\u043A \u0432\u043A\u0440\u0430\u0442\u0446\u0435 \u0438\u043C\u0435\u043D\u0443\u044E\u0442\u0441\u044F \u0447\u0435\u0442\u044B\u0440\u0435 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u044B\u0435.</p></div><div class="stanza"><a href="#s2.50" id="s2.50" class="num">2.50</a><p>\u0418\u0437\u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E \u0434\u0440\u043E\u0431\u044F\u0441\u044C \u0431\u0435\u0441\u0447\u0438\u0441\u043B\u0435\u043D\u043E \u043D\u0430 \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u0438 \u043E\u0434\u043D\u0430 \u0437\u0430 \u0434\u0440\u0443\u0433\u043E\u0439 \u043E\u0442 \u041D\u0430\u0447\u0430\u043B\u0430 \u0438 \u0434\u043E \u0437\u0435\u043C\u043B\u0438 \u0415\u0434\u0438\u043D\u043E\u0435 (\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435) \u043F\u0440\u0438\u0445\u043E\u0434\u0438\u0442 \u0432 \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u0435.</p></div><div class="stanza"><a href="#s2.51" id="s2.51" class="num">2.51</a><p>\u041F\u043E \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438, \u043E\u0434\u043D\u043E \u0437\u0430 \u0434\u0440\u0443\u0433\u0438\u043C \u0432 \u0441\u043B\u043E\u0433\u0430\u0445 \u043C\u0430\u043D\u0442\u0440 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0435\u0442\u0441\u044F \u0441\u043B\u043E\u0433 \u041A\u0428\u0410, \u043F\u0430\u0434\u0430, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u043C\u0438\u0440\u0430 \u041A\u0430\u043B\u0430\u0433\u043D\u0438 \u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u044F \u0433\u0440\u0430\u0434\u043E\u043C \u0412\u0438\u0440\u0430\u0431\u0445\u0430\u0434\u0440\u044B.</p></div><div class="stanza"><a href="#s2.52" id="s2.52" class="num">2.52</a><p>\u041F\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u043C\u044B\u0435 \u0448\u0435\u0441\u0442\u044C \u0430\u0434\u0445\u0432 \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0448\u0435\u0441\u0442\u043D\u0430\u0434\u0446\u0430\u0442\u0438\u0433\u0440\u0430\u0434\u0438\u0435\u043C. \u0412\u0442\u043E\u0440\u044B\u043C\u0438 \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u044E\u0442\u0441\u044F \u0442\u0430\u0442\u0442\u0432\u044B.</p></div><div class="stanza"><a href="#s2.53" id="s2.53" class="num">2.53</a><p>\u0414\u0432\u0430\u0434\u0446\u0430\u0442\u044C \u0442\u0440\u0438 \u0441\u043B\u043E\u0433\u0430 \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441\u043E \u0441\u043B\u043E\u0433\u0430 \u0422\u0430, \u043F\u044F\u0442\u044C \u043F\u0430\u0434 \u0438 \u043C\u0430\u043D\u0442\u0440\u044B \u043E\u0431\u0440\u0430\u0437\u0443\u044E\u0442 \u043F\u044F\u0442\u044C\u0434\u0435\u0441\u044F\u0442 \u0448\u0435\u0441\u0442\u044C \u0433\u043E\u0440\u043E\u0434\u043E\u0432.</p></div><div class="stanza"><a href="#s2.54" id="s2.54" class="num">2.54</a><p>\u041E\u0441\u043E\u0437\u043D\u0430\u0432\u0430\u0435\u043C\u044B\u0435 \u0441\u0435\u043C\u044C \u0442\u0430\u0442\u0442\u0432, \u0447\u0435\u0442\u044B\u0440\u0435 \u0433\u043E\u0440\u043E\u0434\u0430, \u0432 \u0442\u0440\u0435\u0442\u044C\u0435\u043C \u043D\u0430\u0445\u043E\u0434\u044F\u0442\u0441\u044F \u0441\u0435\u043C\u044C \u0432\u0430\u0440\u043D, \u0438 \u043F\u043E\u043F\u0430\u0440\u043D\u043E \u043F\u0430\u0434\u0430 \u0438 \u043C\u0430\u043D\u0442\u0440\u0430.</p></div><div class="stanza"><a href="#s2.55" id="s2.55" class="num">2.55</a><p>\u0412 \u0434\u0435\u0439\u0441\u0442\u0432\u0443\u044E\u0449\u0435\u0439 \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0439 (\u0430\u0434\u0445\u0432\u0435) \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E \u0442\u0440\u0438 \u0442\u0430\u0442\u0442\u0432\u044B \u0432 \u043D\u0435\u0439 \u0432\u044B\u0434\u0435\u043B\u044F\u0435\u0442\u0441\u044F \u0442\u0440\u0438 \u0432\u0430\u0440\u043D\u044B, \u043E\u0434\u043D\u0430 \u043C\u0430\u043D\u0442\u0440\u0430, \u0438 \u043E\u0434\u043D\u0430 \u043F\u0430\u0434\u0430.</p></div><div class="stanza"><a href="#s2.56" id="s2.56" class="num">2.56</a><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0437\u043D\u0430\u0442\u044C \u0432\u043A\u0440\u0430\u0442\u0446\u0435 \u0432\u043E\u0441\u0435\u043C\u043D\u0430\u0434\u0446\u0430\u0442\u044C \u0431\u0445\u0443\u0432\u0430\u043D, \u0438 \u0412\u044B\u0441\u0448\u0443\u044E, \u0428\u0438\u0432\u0430 \u0442\u0430\u0442\u0442\u0432\u0443, \u0448\u0430\u043D\u0442\u0430 (\u043A\u0430\u043B\u0443), \u0434\u0430\u044E\u0449\u0443\u044E (\u0438\u043C) \u043F\u0440\u0438\u0431\u0435\u0436\u0438\u0449\u0435.</p></div><div class="stanza"><a href="#s2.57" id="s2.57" class="num">2.57</a><p>\u0428\u0435\u0441\u0442\u043D\u0430\u0434\u0446\u0430\u0442\u044C \u0433\u043B\u0430\u0441\u043D\u044B\u0445, \u043C\u0430\u043D\u0442\u0440\u0443 \u0438 \u043F\u0430\u0434\u0443 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u0442\u044C \u043A\u0430\u043A \u0415\u0434\u0438\u043D\u043E\u0435. \u0422\u0430\u043A \u0440\u0430\u0441\u0441\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F \u0432\u043A\u0440\u0430\u0442\u0446\u0435 \u043E\u0431 \u0430\u0434\u0445\u0432\u0435 \u0448\u0435\u0441\u0442\u0438 \u0432\u0438\u0434\u043E\u0432.</p></div><div class="stanza"><a href="#s2.58" id="s2.58" class="num">2.58</a><p>\u0418\u0437 \u043D\u0435\u0435 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u0432\u0441\u0435 \u0432\u0435\u043B\u0438\u0447\u0438\u0435 \u043C\u0438\u0440\u043E\u0437\u0434\u0430\u043D\u0438\u044F, \u0432\u0441\u044F \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F, \u0447\u0438\u0441\u0442\u0430\u044F \u0438 \u043D\u0435\u0447\u0438\u0441\u0442\u0430\u044F. \u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u044D\u0442\u0438\u043C \u0447\u0438\u0441\u0442\u044B\u043C (\u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044F\u043C) \u0432\u0441\u0435 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u044B\u0435 \u0438\u043C\u0435\u043D\u0443\u044E\u0442\u0441\u044F \u0447\u0438\u0441\u0442\u044B\u043C\u0438.</p></div><div class="stanza"><a href="#s2.59" id="s2.59" class="num">2.59</a><p>\u0411\u0440\u0430\u0445\u043C\u0430, \u0412\u0438\u0448\u043D\u0443, \u0420\u0443\u0434\u0440\u0430 \u0438 \u0418\u0448\u0432\u0430\u0440\u0430 \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u044E\u0442\u0441\u044F \u0432 \u043D\u0438\u0445 \u043E\u0442\u0434\u0435\u043B\u044C\u043D\u044B\u043C\u0438 \u0447\u0435\u0442\u0440\u0435\u043C\u044F \u0432\u043B\u0430\u0434\u044B\u043A\u0430\u043C\u0438 \u0448\u0430\u043D\u0442\u0430 (\u043A\u0430\u043B\u044B).</p></div><div class="stanza"><a href="#s2.60" id="s2.60" class="num">2.60</a><p>\u0422\u043E, \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u043E, \u0438\u0437 \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442 \u0447\u0442\u043E-\u0442\u043E, \u0441\u0447\u0438\u0442\u0430\u0435\u0442\u0441\u044F \u0431\u043E\u043B\u0435\u0435 \u0432\u044B\u0441\u043E\u043A\u0438\u043C. \u041E\u0431 \u044D\u0442\u043E\u043C \u0442\u0435\u0431\u0435 \u0441\u043A\u0430\u0437\u0430\u043D\u043E \u0432\u0441\u0435. \u041E \u0447\u0435\u043C \u0435\u0449\u0435 \u0436\u0435\u043B\u0430\u0435\u0448\u044C \u0432\u043E\u043F\u0440\u043E\u0441\u0438\u0442\u044C?</p></div><p>\u0422\u0430\u043A\u043E\u0432\u0430 \u0432 \u0441\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u0439 \xAB\u041C\u0430\u043B\u0438\u043D\u0438 \u0432\u0438\u0434\u0436\u0430\u0439\u043E\u0442\u0442\u0430\u0440\u0430 \u0442\u0430\u043D\u0442\u0440\u0435\xBB \u0432\u0442\u043E\u0440\u0430\u044F \u0433\u043B\u0430\u0432\u0430, (\u0438\u043C\u0435\u043D\u0443\u0435\u043C\u0430\u044F) \xAB\u0414\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u0435\xBB.</p>',54),c=[n];function p(l,m,v,t,r,f){return i(),a("div",null,c)}var z=s(e,[["render",p]]);export{h as __pageData,z as default};
